A debounce function limits the rate at which a function can fire by delaying its execution until after a specified wait time has passed since the last invocation.

```javascript
function debounce(func, delay) {
    let timeoutId;
    return function(...args) {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            func.apply(this, args);
        }, delay);
    };
}

// Example usage:
function logMessage(message) {
    console.log(`Message: ${message}`);
}

const debouncedLog = debounce(logMessage, 1000);  // Debounce with 1-second delay

debouncedLog('Hello');  // This won't log immediately
debouncedLog('World');  // This resets the timer; nothing logs yet
// After 1 second of no calls, "Message: World" will be logged once.
```
